  2→// downloading data source files used by the kapow import pipelines.
  3→package fetch
  4→
  5→import (
  6→	"archive/zip"
  7→	"bytes"
  8→	"compress/gzip"
  9→	"context"
 10→	"encoding/json"
 11→	"fmt"
 12→	"io"
 13→	"log/slog"
 14→	"net/http"
