199→// storedFormat returns the archive extension for a given source format,
200→// stripping any outer compression layer (e.g. "csv.gz" → "csv").
201→func storedFormat(format string) string {
202→	switch strings.ToLower(format) {
203→	case "csv.gz", "gz":
204→		return "csv"
205→	case "zip":
206→		return "csv"
207→	default:
208→		return format
209→	}
210→}
