248→// compressXZ reads from src and writes an xz-compressed file to dst using the
249→// system xz binary with -9e (maximum/extreme compression).
250→func compressXZ(ctx context.Context, src io.Reader, dst string) error {
251→	f, err := os.Create(dst)
252→	if err != nil {
253→		return fmt.Errorf("create xz output: %w", err)
254→	}
255→	defer f.Close()
256→
257→	var stderr bytes.Buffer
258→	cmd := exec.CommandContext(ctx, "xz", "-9e", "-c") //nolint:gosec
259→	cmd.Stdin = src
260→	cmd.Stdout = f
261→	cmd.Stderr = &stderr
262→
263→	if err := cmd.Run(); err != nil {
264→		_ = os.Remove(dst)
265→		return fmt.Errorf("xz: %w: %s", err, strings.TrimSpace(stderr.String()))
266→	}
267→	return nil
268→}
